+    const Buffer = BufferImpl(SimpleBufferConfig);
+
+    var data = [_]u8{1, 2, 3, 4, 5};
+    var buffer = try Buffer.init(allocator, @ptrCast(&data), 5, false);
+    defer buffer.deinit();
+
+    try testing.expectEqual(@as(isize, 5), buffer.len);
