+}
+
+test "multi-dimensional buffer" {
+    const testing = std.testing;
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    const Buffer = BufferImpl(NDArrayBufferConfig);
+
+    var data = [_]i32{1, 2, 3, 4, 5, 6};
